-- lezen — Kennismaken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000001', 'A1', 'lezen', 'Kennismaken: wie ben jij?',
  'Je leert een korte tekst lezen waarin mensen zich aan elkaar voorstellen.', 20, true, '{"intro":"In deze les lees je over kennismaken. Je leert hoe mensen zeggen wie zij zijn en waar zij wonen. Je oefent met heel simpele zinnen.","learningGoals":["Je begrijpt een korte tekst over kennismaken.","Je herkent woorden zoals naam, wonen en komen uit.","Je begrijpt vragen zoals Hoe heet je? en Waar woon je?","Je vindt informatie over een persoon in een tekst."],"vocabulary":[{"word":"kennismaken","explanation":"Voor de eerste keer met iemand praten. Je leert een nieuw persoon kennen.","example":"Ik wil graag kennismaken met de buren."},{"word":"heten","explanation":"De naam hebben. Je zegt zo hoe je naam is.","example":"Ik heet Sara en jij?"},{"word":"aangenaam","explanation":"Dit zeg je als je iemand voor de eerste keer ontmoet. Het is beleefd.","example":"Hallo, ik ben Tom. Aangenaam."},{"word":"wonen","explanation":"Op een plek zijn waar je slaapt en leeft, bijvoorbeeld in een stad of een huis.","example":"Wij wonen in Utrecht."},{"word":"komen uit","explanation":"Zeggen uit welk land of welke stad je bent.","example":"Ik kom uit Marokko."},{"word":"ontmoeten","explanation":"Iemand zien en met die persoon praten.","example":"Ik ontmoet vandaag nieuwe mensen in de klas."},{"word":"aardig","explanation":"Vriendelijk en lief tegen andere mensen.","example":"De docent is heel aardig."},{"word":"de klas","explanation":"De groep mensen die samen les krijgt, of de kamer waar je les krijgt.","example":"In de klas zitten veel cursisten."}],"grammar":[{"heading":"Het werkwoord zijn","body":"Met het werkwoord zijn zeg je wie of hoe je bent. Ik ben, jij bent, hij/zij is. Voorbeeld: Ik ben Sara. Zij is drie jaar oud."},{"heading":"Vragen met Hoe en Waar","body":"Met Hoe en Waar stel je een vraag. Voorbeeld: Hoe heet je? Waar woon je? Het werkwoord komt na het vraagwoord."}],"exampleSentences":["Hallo, ik ben Nour.","Ik kom uit Iran en ik woon nu in Rotterdam.","Hoe heet jij?","Aangenaam, leuk je te ontmoeten.","Mijn buurvrouw is heel aardig."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000001', 'reading_text', 'Lees de tekst.', '{"text":"Hallo, ik ben Sara. Ik kom uit Syrië. Nu woon ik in Utrecht. Ik ben 28 jaar oud. Ik heb een man en een dochter. Mijn man heet Omar. Onze dochter heet Lina. Zij is drie jaar oud. Vandaag ga ik naar de taalles. Daar leer ik Nederlands. In de klas zitten veel mensen. Zij komen uit veel landen. De docent heet meneer De Vries. Hij is heel aardig. Ik zeg: Hallo, ik ben Sara. Aangenaam. De vrouw naast mij zegt: Hoi, ik ben Fatima. Wij praten samen. Het is leuk om nieuwe mensen te ontmoeten. Ik ben blij."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000001', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waar komt Sara vandaan?","options":["Uit Syrië","Uit Utrecht","Uit Nederland","Uit Marokko"]}'::jsonb, '{"correctIndex":0,"explanation":"In de tekst staat: Ik kom uit Syrië. Utrecht is de stad waar zij nu woont."}'::jsonb, 2
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000001', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoe heet de dochter van Sara?","options":["Fatima","Lina","Sara","Omar"]}'::jsonb, '{"correctIndex":1,"explanation":"In de tekst staat: Onze dochter heet Lina. Omar is haar man."}'::jsonb, 3
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000001', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoe voelt Sara zich aan het einde van de tekst?","options":["Boos","Moe","Blij","Verdrietig"]}'::jsonb, '{"correctIndex":2,"explanation":"De laatste zin is: Ik ben blij. Zij vindt het leuk om nieuwe mensen te ontmoeten."}'::jsonb, 4
);

-- luisteren — Kennismaken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000002', 'A1', 'luisteren', 'Kennismaken: hallo zeggen en jezelf voorstellen',
  'Je leert luisteren naar een gesprek waarin twee mensen elkaar voor het eerst ontmoeten.', 20, true, '{"intro":"In deze les leer je luisteren als mensen elkaar ontmoeten. Je hoort hoe iemand hallo zegt en zijn naam vertelt. Je leert ook hoe je vraagt hoe iemand heet en waar iemand woont.","learningGoals":["Je begrijpt een korte begroeting.","Je herkent hoe iemand zijn naam zegt.","Je begrijpt een vraag over waar iemand woont.","Je begrijpt woorden om afscheid te nemen."],"vocabulary":[{"word":"hallo","explanation":"Dit zeg je als je iemand ziet en begroet.","example":"Hallo, ik ben Sara."},{"word":"hoe heet je?","explanation":"Zo vraag je wat de naam van iemand is.","example":"Hoe heet je? Ik heet Tom."},{"word":"ik heet","explanation":"Zo zeg je wat je naam is.","example":"Ik heet Lisa."},{"word":"aangenaam","explanation":"Dit zeg je als je iemand voor het eerst ontmoet. Het is beleefd.","example":"Aangenaam, ik ben Karim."},{"word":"waar woon je?","explanation":"Zo vraag je in welke stad of plaats iemand woont.","example":"Waar woon je? Ik woon in Utrecht."},{"word":"wonen","explanation":"Dit betekent dat je op een plaats bent waar je slaapt en leeft.","example":"Ik woon in Amsterdam."},{"word":"tot ziens","explanation":"Dit zeg je als je weggaat en iemand later weer ziet.","example":"Tot ziens, tot morgen!"},{"word":"dank je wel","explanation":"Dit zeg je als iemand aardig voor je is of je iets geeft.","example":"Dank je wel voor de koffie."}],"grammar":[{"heading":"Het werkwoord in de tegenwoordige tijd (ik / jij)","body":"Bij ''ik'' gebruik je de stam: ik woon, ik heet. Bij ''jij'' komt er een -t bij: jij woont, jij heet. Bijvoorbeeld: Ik woon in Rotterdam. Jij woont in Den Haag."},{"heading":"Vragen met een vraagwoord","body":"Een vraag begint vaak met een vraagwoord: hoe, waar, wat. Daarna komt het werkwoord en dan ''je''. Bijvoorbeeld: Hoe heet je? Waar woon je?"}],"exampleSentences":["Hallo, ik heet Anna.","Hoe heet je?","Ik woon in Eindhoven.","Aangenaam, leuk je te ontmoeten.","Tot ziens en fijne dag!"]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000002', 'listening_clip', 'Beluister het gesprek.', '{"dialogue":[{"speaker":"v","name":"Sara","text":"Hallo, ik ben Sara. Hoe heet je?"},{"speaker":"m","name":"Tom","text":"Hallo Sara. Ik heet Tom. Aangenaam."},{"speaker":"v","name":"Sara","text":"Aangenaam, Tom. Waar woon je?"},{"speaker":"m","name":"Tom","text":"Ik woon in Utrecht. En jij?"},{"speaker":"v","name":"Sara","text":"Ik woon in Amsterdam. Ben je hier voor de cursus?"},{"speaker":"m","name":"Tom","text":"Ja, ik leer Nederlands. Jij ook?"},{"speaker":"v","name":"Sara","text":"Ja, ik leer ook Nederlands. Het is leuk hier."},{"speaker":"m","name":"Tom","text":"Dat vind ik ook. Tot ziens, Sara!"},{"speaker":"v","name":"Sara","text":"Tot ziens, Tom. Fijne dag!"}]}'::jsonb, null, 1
);
