-- schrijven — Kennismaken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000003', 'A1', 'schrijven', 'Kennismaken: jezelf voorstellen',
  'Je leert korte zinnen schrijven om jezelf voor te stellen aan een nieuw persoon.', 20, true, '{"intro":"In deze les leer je hoe je jezelf voorstelt. Je oefent met korte zinnen over je naam, je land en waar je woont. Zo kun je een kort bericht schrijven aan iemand die je nog niet kent.","learningGoals":["Je kunt je naam en leeftijd opschrijven.","Je kunt schrijven waar je vandaan komt.","Je kunt schrijven waar je woont.","Je kunt een korte begroeting schrijven."],"vocabulary":[{"word":"hallo","explanation":"Dit zeg of schrijf je als je iemand begroet.","example":"Hallo, ik ben Sara."},{"word":"de naam","explanation":"Zo heet je. Andere mensen roepen je met je naam.","example":"Mijn naam is Omar."},{"word":"wonen","explanation":"In een huis of stad zijn waar je slaapt en leeft.","example":"Ik woon in Utrecht."},{"word":"het land","explanation":"Een groot gebied met een naam, zoals Nederland of Marokko.","example":"Mijn land is Syrië."},{"word":"komen uit","explanation":"Zeggen waar je geboren bent of waar je vandaan gaat.","example":"Ik kom uit Polen."},{"word":"de leeftijd","explanation":"Hoeveel jaar je oud bent.","example":"Mijn leeftijd is dertig jaar."},{"word":"aangenaam","explanation":"Dit schrijf je als je blij bent om iemand te leren kennen.","example":"Aangenaam, ik ben Lin."},{"word":"de groetjes","explanation":"Dit schrijf je aan het einde van een bericht.","example":"Groetjes, Ahmed."}],"grammar":[{"heading":"Ik ben en ik heet","body":"Met ''ik ben'' en ''ik heet'' zeg je je naam. Bijvoorbeeld: Ik ben Fatima. Ik heet Fatima. Beide zinnen zijn goed."},{"heading":"Werkwoord op plaats twee","body":"In een zin staat het werkwoord op de tweede plaats. Bijvoorbeeld: Ik woon in Rotterdam. Nu woon ik in Rotterdam. Het woord ''woon'' blijft op plaats twee."}],"exampleSentences":["Hallo, ik ben Nadia.","Ik kom uit Irak.","Ik woon nu in Den Haag.","Ik ben achtentwintig jaar oud.","Aangenaam kennis te maken!"]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000003', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een kort bericht aan een nieuwe klasgenoot. Stel jezelf voor. Schrijf je naam, hoe oud je bent, uit welk land je komt en waar je nu woont. Begin met ''Hallo'' en eindig met ''Groetjes'' en je naam.","minWords":35}'::jsonb, null, 1
);

-- spreken — Kennismaken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000004', 'A1', 'spreken', 'Kennismaken: jezelf voorstellen',
  'Je leert jezelf voorstellen en iemand nieuw begroeten in het Nederlands.', 20, true, '{"intro":"In deze les leer je kennismaken met andere mensen. Je zegt je naam en je vraagt hoe iemand heet. Je leert ook waar je vandaan komt.","learningGoals":["Je kunt jezelf voorstellen.","Je kunt vragen hoe iemand heet.","Je kunt zeggen waar je vandaan komt.","Je kunt iemand begroeten en gedag zeggen."],"vocabulary":[{"word":"hallo","explanation":"Dit zeg je als je iemand begroet.","example":"Hallo, ik ben Sara."},{"word":"de naam","explanation":"Zo heet je. Iedereen heeft een naam.","example":"Mijn naam is Omar."},{"word":"heten","explanation":"Dit gebruik je om je naam te zeggen.","example":"Ik heet Lisa. Hoe heet jij?"},{"word":"aangenaam","explanation":"Dit zeg je als je iemand nieuw ontmoet. Het is beleefd.","example":"Aangenaam, ik ben je nieuwe buurman."},{"word":"wonen","explanation":"Dit is de plek waar je huis is.","example":"Ik woon in Utrecht."},{"word":"vandaan komen","explanation":"Dit is het land of de stad waar je geboren bent.","example":"Ik kom uit Marokko. Waar kom jij vandaan?"},{"word":"de vriend","explanation":"Een persoon die je aardig vindt en goed kent.","example":"Dit is mijn vriend Tom."},{"word":"tot ziens","explanation":"Dit zeg je als je weggaat.","example":"Tot ziens, tot morgen!"}],"grammar":[{"heading":"Het werkwoord zijn","body":"Je gebruikt ''zijn'' om te zeggen wie je bent. Ik ben, jij bent, hij/zij is. Bijvoorbeeld: Ik ben Ali. Zij is mijn zus."},{"heading":"Vragen met hoe en waar","body":"Een vraag begint vaak met een vraagwoord. ''Hoe heet je?'' vraag je naar de naam. ''Waar woon je?'' vraag je naar de plek."}],"exampleSentences":["Hallo, ik ben Fatima.","Hoe heet jij?","Ik kom uit Syrië en ik woon nu in Amsterdam.","Aangenaam kennis te maken.","Tot ziens en fijne dag!"]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000004', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je bent op een taalcursus. Je ontmoet een nieuwe medecursist. Stel jezelf voor en maak kennis.","expectedPoints":["Begroet de ander: ''Hallo'' of ''Goedemorgen''.","Zeg je naam: ''Ik heet ...'' of ''Ik ben ...''.","Vraag naar de ander: ''Hoe heet jij?'' en ''Waar kom je vandaan?''.","Zeg gedag: ''Tot ziens'' of ''Tot later''."]}'::jsonb, null, 1
);

-- lezen — Familie
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000005', 'A1', 'lezen', 'Mijn familie',
  'In deze les leer je eenvoudige woorden en zinnen over de familie te lezen.', 21, false, '{"intro":"In deze les lees je over een familie. Je leert woorden zoals vader, moeder, broer en zus. Je oefent met korte, simpele zinnen.","learningGoals":["Je kent belangrijke woorden over de familie.","Je begrijpt een korte tekst over een gezin.","Je kunt vragen over de tekst beantwoorden.","Je leert het werkwoord ''hebben'' gebruiken."],"vocabulary":[{"word":"de familie","explanation":"alle mensen die bij elkaar horen, zoals vader, moeder en kinderen","example":"Mijn familie woont in Utrecht."},{"word":"de vader","explanation":"de man met kinderen; ook: papa","example":"Mijn vader heet Peter."},{"word":"de moeder","explanation":"de vrouw met kinderen; ook: mama","example":"Mijn moeder maakt het eten."},{"word":"de broer","explanation":"een jongen of man met dezelfde ouders als jij","example":"Mijn broer is tien jaar."},{"word":"de zus","explanation":"een meisje of vrouw met dezelfde ouders als jij","example":"Mijn zus heet Lisa."},{"word":"de oma","explanation":"de moeder van je vader of je moeder","example":"Mijn oma maakt lekkere soep."},{"word":"de opa","explanation":"de vader van je vader of je moeder","example":"Opa speelt in de tuin."},{"word":"de hond","explanation":"een dier dat veel mensen thuis hebben","example":"De hond heet Max."}],"grammar":[{"heading":"Het werkwoord ''hebben''","body":"Je gebruikt ''hebben'' om te zeggen wat je bezit. Ik heb een broer. Wij hebben een hond."},{"heading":"Bezittelijk voornaamwoord ''mijn''","body":"Met ''mijn'' zeg je dat iets van jou is. Mijn vader heet Peter. Mijn zus is zestien jaar."}],"exampleSentences":["Ik heb een broer en een zus.","Mijn moeder heet Els.","Wij hebben een hond.","Mijn oma en opa wonen in Amsterdam.","Ik hou veel van mijn familie."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000005', 'reading_text', 'Lees de tekst.', '{"text":"Ik heet Sanne. Ik woon in Utrecht met mijn familie. Mijn vader heet Peter en mijn moeder heet Els. Ik heb een broer en een zus. Mijn broer heet Tom. Hij is tien jaar. Mijn zus heet Lisa. Zij is zestien jaar. Ik ben veertien jaar. Wij hebben ook een hond. De hond heet Max. In het weekend gaan wij naar mijn oma en opa. Zij wonen in Amsterdam. Mijn oma maakt lekkere soep. Opa speelt met de hond in de tuin. Ik hou veel van mijn familie. Wij zijn samen heel blij."}'::jsonb, null, 1
);
