-- schrijven — Familie
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000007', 'A1', 'schrijven', 'Schrijven over je familie',
  'Je leert eenvoudige zinnen schrijven over de mensen in je familie.', 21, false, '{"intro":"In deze les leer je schrijven over je familie. Je leert woorden voor familieleden. Daarna schrijf je zelf een kort bericht over jouw familie.","learningGoals":["Je kent woorden voor familieleden.","Je kunt vertellen wie er in je familie is.","Je kunt de leeftijd en naam van een persoon opschrijven.","Je kunt een kort bericht over je familie schrijven."],"vocabulary":[{"word":"de familie","explanation":"alle mensen die bij elkaar horen, zoals je vader en moeder","example":"Mijn familie is groot."},{"word":"de vader","explanation":"de man, hij is jouw ouder","example":"Mijn vader werkt in een winkel."},{"word":"de moeder","explanation":"de vrouw, zij is jouw ouder","example":"Mijn moeder kookt lekker eten."},{"word":"de broer","explanation":"een jongen of man, hij heeft dezelfde ouders als jij","example":"Ik heb een broer van tien jaar."},{"word":"de zus","explanation":"een meisje of vrouw, zij heeft dezelfde ouders als jij","example":"Mijn zus woont in Utrecht."},{"word":"het kind","explanation":"een jongen of meisje, nog niet groot","example":"Wij hebben een kind."},{"word":"de opa","explanation":"de vader van je vader of moeder","example":"Mijn opa is oud en aardig."},{"word":"de oma","explanation":"de moeder van je vader of moeder","example":"Mijn oma maakt soep voor ons."},{"word":"getrouwd","explanation":"je bent samen met een man of vrouw voor de wet","example":"Mijn broer is getrouwd."}],"grammar":[{"heading":"Bezit: mijn, jouw, zijn, haar","body":"Je gebruikt ''mijn'' voor jezelf en ''jouw'' voor de ander. Voor een man gebruik je ''zijn'' en voor een vrouw ''haar''. Voorbeeld: Mijn vader heet Ali. Zijn zus woont in Rotterdam. Haar moeder is aardig."},{"heading":"Het werkwoord hebben","body":"Met ''hebben'' zeg je wie er in je familie is. Ik heb, jij hebt, hij/zij heeft, wij hebben. Voorbeeld: Ik heb een broer. Wij hebben twee kinderen."}],"exampleSentences":["Mijn familie woont in Nederland.","Ik heb een broer en een zus.","Mijn moeder heet Fatima en zij is 45 jaar.","Mijn opa en oma wonen ver weg.","Wij hebben een klein kind van twee jaar."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000007', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een kort bericht aan een nieuwe vriend over jouw familie. Vertel wie er in je familie is. Schrijf de namen en de leeftijd van twee personen. Gebruik de woorden ''mijn'', ''vader'', ''moeder'', ''broer'' of ''zus''. Begin met ''Hoi'' en eindig met je naam.","minWords":40}'::jsonb, null, 1
);

-- spreken — Familie
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000008', 'A1', 'spreken', 'Praten over je familie',
  'In deze les leer je in eenvoudig Nederlands over je familie praten.', 21, false, '{"intro":"In deze les leer je woorden over de familie. Je leert vertellen wie er in jouw familie zijn. Je oefent met korte, makkelijke zinnen.","learningGoals":["Je kent woorden voor familieleden.","Je kunt vertellen hoeveel broers en zussen je hebt.","Je kunt de namen van je familie noemen.","Je kunt een korte vraag over familie stellen."],"vocabulary":[{"word":"de familie","explanation":"alle mensen die bij elkaar horen, zoals ouders en kinderen","example":"Mijn familie woont in Nederland."},{"word":"de vader","explanation":"de man, hij is jouw ouder","example":"Mijn vader heet Jan."},{"word":"de moeder","explanation":"de vrouw, zij is jouw ouder","example":"Mijn moeder werkt in een winkel."},{"word":"de broer","explanation":"een jongen of man met dezelfde ouders als jij","example":"Ik heb een broer van tien jaar."},{"word":"de zus","explanation":"een meisje of vrouw met dezelfde ouders als jij","example":"Mijn zus woont in Amsterdam."},{"word":"het kind","explanation":"een jongen of meisje, nog niet groot","example":"Wij hebben een kind."},{"word":"de opa","explanation":"de vader van jouw vader of moeder","example":"Mijn opa is zeventig jaar."},{"word":"de oma","explanation":"de moeder van jouw vader of moeder","example":"Mijn oma maakt lekkere soep."},{"word":"getrouwd","explanation":"je hebt een man of een vrouw voor het leven","example":"Mijn broer is getrouwd."}],"grammar":[{"heading":"Bezittelijk voornaamwoord: mijn en jouw","body":"Je gebruikt ''mijn'' voor iets van jou. Je gebruikt ''jouw'' voor iets van de ander. Voorbeeld: Mijn moeder heet Anna. Hoe heet jouw broer?"},{"heading":"Het werkwoord hebben","body":"Met ''hebben'' zeg je wat je hebt. Ik heb, jij hebt, hij heeft. Voorbeeld: Ik heb een zus. Zij heeft twee kinderen."}],"exampleSentences":["Ik heb een broer en een zus.","Mijn vader heet Peter.","Mijn oma woont in Rotterdam.","Wij zijn thuis met vier mensen.","Hoeveel kinderen heb jij?"]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000008', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je bent op een taalles. De docent vraagt je om over je familie te vertellen. Je vertelt wie er in je familie zijn en waar ze wonen.","expectedPoints":["Ik heb een vader en een moeder.","Ik heb een broer en twee zussen.","Mijn familie woont in Nederland.","Mijn moeder heet Sara en mijn vader heet Ali."]}'::jsonb, null, 1
);

-- lezen — Getallen en tijd
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000009', 'A1', 'lezen', 'Getallen en tijd lezen',
  'Je leert getallen en tijden lezen en begrijpen in het Nederlands.', 22, false, '{"intro":"In deze les leer je over getallen en tijd. Je leert hoe laat het is. Je leest ook over de dagen van de week.","learningGoals":["Je kunt getallen van 1 tot 100 lezen.","Je kunt de tijd op een klok lezen.","Je kent de dagen van de week.","Je begrijpt korte zinnen over tijd."],"vocabulary":[{"word":"het getal","explanation":"Een getal is bijvoorbeeld 1, 2 of 3.","example":"Het getal tien is groter dan vijf."},{"word":"de tijd","explanation":"De tijd is hoe laat het is.","example":"Ik heb geen tijd, ik ben laat."},{"word":"de klok","explanation":"Op de klok zie je hoe laat het is.","example":"De klok hangt aan de muur."},{"word":"het uur","explanation":"Een dag heeft vierentwintig uur.","example":"De les duurt een uur."},{"word":"de minuut","explanation":"Een uur heeft zestig minuten.","example":"Wacht een minuut, ik kom eraan."},{"word":"de dag","explanation":"Een week heeft zeven dagen.","example":"Vandaag is een mooie dag."},{"word":"de week","explanation":"Een week is maandag tot en met zondag.","example":"Volgende week ga ik naar school."},{"word":"vroeg","explanation":"Vroeg is aan het begin van de dag.","example":"Ik sta vroeg op, om zes uur."},{"word":"laat","explanation":"Laat is niet op tijd of aan het eind van de dag.","example":"Het is al laat, ik ga naar bed."},{"word":"hoe laat","explanation":"Dit vraag je als je de tijd wilt weten.","example":"Hoe laat is het nu?"}],"grammar":[{"heading":"Hoe laat is het?","body":"Je zegt de tijd met ''het is'' en dan het uur. Voorbeeld: Het is drie uur. Het is half acht. Voor kwart gebruik je: Het is kwart over vier."},{"heading":"Getallen als woord","body":"Kleine getallen schrijf je vaak als woord. Voorbeeld: een, twee, drie, vier, vijf. Grotere getallen ook: tien, twintig, dertig."}],"exampleSentences":["Het is nu acht uur.","De winkel gaat om negen uur open.","Een week heeft zeven dagen.","Ik werk vijf dagen per week.","De bus komt om half tien."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000009', 'reading_text', 'Lees de tekst.', '{"text":"Anna staat elke dag vroeg op. Om zeven uur begint haar dag. Zij eet brood en drinkt koffie. Om half negen gaat zij naar de les. De les duurt twee uur. Anna leert Nederlands van maandag tot en met vrijdag. In het weekend heeft zij geen les. Op zaterdag en zondag is zij vrij. Na de les eet zij om twaalf uur. Dan gaat zij naar huis. Om drie uur doet zij boodschappen. De winkel is open tot zes uur. ''s Avonds kookt Anna eten. Om tien uur gaat zij naar bed. Anna heeft altijd genoeg tijd voor alles."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000009', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoe laat begint de dag van Anna?","options":["Om zes uur","Om zeven uur","Om acht uur","Om negen uur"]}'::jsonb, '{"correctIndex":1,"explanation":"In de tekst staat: ''Om zeven uur begint haar dag.''"}'::jsonb, 2
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000009', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wanneer heeft Anna geen les?","options":["Op maandag","Op vrijdag","In het weekend","Op woensdag"]}'::jsonb, '{"correctIndex":2,"explanation":"In de tekst staat: ''In het weekend heeft zij geen les.''"}'::jsonb, 3
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000009', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoe lang duurt de les van Anna?","options":["Een uur","Twee uur","Drie uur","Vier uur"]}'::jsonb, '{"correctIndex":1,"explanation":"In de tekst staat: ''De les duurt twee uur.''"}'::jsonb, 4
);

-- luisteren — Getallen en tijd
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000010', 'A1', 'luisteren', 'Getallen en tijd luisteren',
  'Je leert getallen en tijd verstaan in eenvoudige gesprekken.', 22, false, '{"intro":"In deze les luister je naar getallen en tijd. Je hoort hoe laat het is en hoeveel iets kost. Je oefent met simpele zinnen die je elke dag hoort.","learningGoals":["Je verstaat de getallen van 0 tot 20.","Je begrijpt vragen over de tijd.","Je hoort hoe laat iets begint.","Je verstaat een prijs of een telefoonnummer."],"vocabulary":[{"word":"hoe laat","explanation":"Je vraagt naar de tijd op de klok.","example":"Hoe laat is het nu?"},{"word":"de klok","explanation":"Een klok laat de tijd zien.","example":"Ik kijk op de klok."},{"word":"het uur","explanation":"Een dag heeft vierentwintig uur.","example":"De les duurt een uur."},{"word":"half","explanation":"Half betekent dertig minuten voor het hele uur.","example":"Het is half acht."},{"word":"getal","explanation":"Een getal is een cijfer, zoals een, twee of drie.","example":"Tien is een groot getal."},{"word":"de euro","explanation":"In Nederland betaal je met euro.","example":"Het brood kost twee euro."},{"word":"kosten","explanation":"Kosten zegt hoeveel geld je betaalt.","example":"Hoeveel kost de koffie?"},{"word":"beginnen","explanation":"Iets start op een tijd.","example":"De film begint om acht uur."},{"word":"de minuut","explanation":"Een uur heeft zestig minuten.","example":"Ik wacht vijf minuten."}],"grammar":[{"heading":"Hoe laat is het?","body":"Je zegt de tijd met ''om'' en het uur. Voorbeeld: ''Het is drie uur.'' en ''De trein komt om half vier.''"},{"heading":"Getallen 0 tot 20","body":"Je telt: een, twee, drie, vier, vijf... tot twintig. Voorbeeld: ''Ik heb tien euro.'' en ''Er zijn vijftien mensen.''"}],"exampleSentences":["Het is nu half negen.","De winkel gaat om negen uur open.","De koffie kost twee euro vijftig.","Mijn nummer is nul zes, twaalf, drieënvijftig.","De bus komt over vijf minuten."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000010', 'listening_clip', 'Beluister het gesprek.', '{"dialogue":[{"speaker":"v","name":"Sanne","text":"Hoi Tom, hoe laat is het nu?"},{"speaker":"m","name":"Tom","text":"Het is half acht."},{"speaker":"v","name":"Sanne","text":"Oké. Hoe laat begint de film?"},{"speaker":"m","name":"Tom","text":"De film begint om acht uur."},{"speaker":"v","name":"Sanne","text":"En hoeveel kost een kaartje?"},{"speaker":"m","name":"Tom","text":"Een kaartje kost tien euro."},{"speaker":"v","name":"Sanne","text":"Prima. De bus komt over vijf minuten."},{"speaker":"m","name":"Tom","text":"Goed, dan zijn we op tijd. We gaan!"}]}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000010', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoe laat is het in het gesprek?","options":["Half acht","Acht uur","Half negen","Tien uur"]}'::jsonb, '{"correctIndex":0,"explanation":"Tom zegt: ''Het is half acht.''"}'::jsonb, 2
);
