  'a1c00000-0000-4000-8000-000000000010', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoe laat begint de film?","options":["Half acht","Zeven uur","Acht uur","Negen uur"]}'::jsonb, '{"correctIndex":2,"explanation":"Tom zegt: ''De film begint om acht uur.''"}'::jsonb, 3
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000010', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoeveel kost een kaartje?","options":["Vijf euro","Tien euro","Twaalf euro","Twintig euro"]}'::jsonb, '{"correctIndex":1,"explanation":"Tom zegt: ''Een kaartje kost tien euro.''"}'::jsonb, 4
);

-- schrijven — Getallen en tijd
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000011', 'A1', 'schrijven', 'Getallen en tijd: hoe laat is het?',
  'Je leert getallen en de tijd opschrijven in eenvoudig Nederlands.', 22, false, '{"intro":"In deze les leer je getallen en de tijd. Je leert hoe laat het is en welke dag het is. Je oefent met korte zinnen over tijd.","learningGoals":["Je kunt getallen van 0 tot 20 opschrijven.","Je kunt zeggen en schrijven hoe laat het is.","Je kunt de dagen van de week noemen.","Je kunt een kort bericht over tijd schrijven."],"vocabulary":[{"word":"hoe laat","explanation":"Je vraagt naar de tijd.","example":"Hoe laat is het nu?"},{"word":"het uur","explanation":"Een dag heeft 24 uur.","example":"Ik werk acht uur per dag."},{"word":"de minuut","explanation":"Een uur heeft 60 minuten.","example":"Ik ben over vijf minuten klaar."},{"word":"half","explanation":"Dit is een half uur, dus 30 minuten.","example":"Het is half twee."},{"word":"de dag","explanation":"Een week heeft zeven dagen.","example":"Welke dag is het vandaag?"},{"word":"vandaag","explanation":"Dit is de dag van nu.","example":"Vandaag is het maandag."},{"word":"morgen","explanation":"Dit is de dag na vandaag.","example":"Morgen ga ik naar school."},{"word":"de week","explanation":"Een week heeft zeven dagen, van maandag tot zondag.","example":"Ik heb deze week een afspraak."},{"word":"vroeg","explanation":"Vroeg is aan het begin van de dag.","example":"Ik sta vroeg op, om zeven uur."},{"word":"laat","explanation":"Laat is aan het eind van de dag.","example":"Het is al laat, ik ga slapen."}],"grammar":[{"heading":"Hoe laat is het? De tijd zeggen","body":"Je zegt eerst het uur en dan ''uur''. Voorbeeld: ''Het is drie uur.'' Voor een half uur zeg je ''half'' plus het volgende uur. Voorbeeld: half vier is 3:30. Voor kwart zeg je ''kwart over'' of ''kwart voor''. Voorbeeld: ''Het is kwart over vijf'' (5:15)."},{"heading":"Getallen schrijven","body":"Je schrijft kleine getallen vaak als woord: een, twee, drie, vier, vijf. Grotere getallen kun je met cijfers schrijven: 12, 15, 20. Voorbeeld: ''Ik heb twee kinderen.'' of ''De bus komt om 8 uur.''"}],"exampleSentences":["Het is nu tien uur.","De les begint om half negen.","Vandaag is het dinsdag.","Ik sta elke dag om zeven uur op.","De winkel is open van negen tot vijf uur."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000011', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een kort bericht aan een vriend. Vertel welke dag het vandaag is en hoe laat je afspreekt. Schrijf ook waar jullie elkaar zien en hoe laat je thuis bent. Gebruik minstens drie getallen of tijden.","minWords":40}'::jsonb, null, 1
);

-- spreken — Getallen en tijd
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000012', 'A1', 'spreken', 'Getallen en tijd: hoe laat is het?',
  'Je leert tellen en vertellen hoe laat het is in eenvoudig Nederlands.', 22, false, '{"intro":"In deze les leer je getallen zeggen. Ook leer je vragen en zeggen hoe laat het is. Je oefent met spreken over tijd in het dagelijks leven.","learningGoals":["Je kunt tellen van 1 tot 20.","Je kunt vragen hoe laat het is.","Je kunt zeggen hoe laat het is.","Je kunt over jouw dag en tijden praten."],"vocabulary":[{"word":"het getal","explanation":"Een teken voor tellen, zoals 1, 2 of 3.","example":"Het getal drie komt na twee."},{"word":"tellen","explanation":"Getallen op volgorde zeggen: een, twee, drie.","example":"Ik tel tot tien."},{"word":"de tijd","explanation":"Het uur van de dag, wat de klok zegt.","example":"Ik heb geen tijd, ik moet gaan."},{"word":"de klok","explanation":"Een ding aan de muur dat de tijd laat zien.","example":"De klok hangt boven de deur."},{"word":"het uur","explanation":"Een deel van de dag; een dag heeft 24 uur.","example":"Ik werk acht uur per dag."},{"word":"de minuut","explanation":"Een klein stukje tijd; een uur heeft 60 minuten.","example":"Wacht een minuut, ik kom eraan."},{"word":"half","explanation":"De helft; bij tijd is het 30 minuten.","example":"Het is half acht."},{"word":"kwart","explanation":"Een kwart is 15 minuten.","example":"Het is kwart over drie."},{"word":"vroeg","explanation":"Aan het begin van de dag of eerder dan normaal.","example":"Ik sta vroeg op, om zes uur."},{"word":"laat","explanation":"Aan het einde van de dag of later dan normaal.","example":"Het is al laat, ik ga naar bed."}],"grammar":[{"heading":"Hoe laat is het?","body":"Je vraagt de tijd met: Hoe laat is het? Je antwoordt met: Het is ... . Bijvoorbeeld: Het is drie uur. Het is half vijf."},{"heading":"Over, voor, half en kwart","body":"Voor de tijd gebruik je ''over'' en ''voor''. Bijvoorbeeld: tien over twee (2:10) en tien voor drie (2:50). Ook zeg je ''half'' en ''kwart'': half vier (3:30) en kwart over vier (4:15)."}],"exampleSentences":["Ik tel van een tot tien.","Hoe laat is het nu?","Het is kwart over negen.","De bus komt om half acht.","Ik sta elke dag om zeven uur op."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000012', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je bent op het station. Je vraagt aan iemand hoe laat de trein naar Utrecht vertrekt. Je zegt ook hoe laat het nu is.","expectedPoints":["Zeg hallo en vraag: Hoe laat vertrekt de trein naar Utrecht?","Zeg hoe laat het nu is, bijvoorbeeld: Het is nu tien over twee.","Vraag van welk spoor de trein gaat.","Zeg dank je wel en tot ziens."]}'::jsonb, null, 1
);

-- lezen — Eten en drinken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000013', 'A1', 'lezen', 'Eten en drinken',
  'In deze les lees je eenvoudige teksten over eten en drinken in het dagelijks leven.', 23, false, '{"intro":"In deze les leer je woorden over eten en drinken. Je leest korte, makkelijke zinnen over ontbijt, lunch en avondeten. Zo begrijp je snel een simpele tekst over eten.","learningGoals":["Je herkent veelgebruikte woorden over eten en drinken.","Je begrijpt een korte, eenvoudige tekst over maaltijden.","Je kunt vragen over de tekst beantwoorden.","Je leest zinnen in de tegenwoordige tijd."],"vocabulary":[{"word":"het ontbijt","explanation":"Het eten in de ochtend.","example":"Ik eet brood bij het ontbijt."},{"word":"de lunch","explanation":"Het eten in de middag.","example":"Voor de lunch eet ik een boterham."},{"word":"het avondeten","explanation":"Het warme eten in de avond.","example":"Wij koken samen het avondeten."},{"word":"het water","explanation":"Iets dat je drinkt. Het heeft geen kleur.","example":"Zij drinkt een glas water."},{"word":"de koffie","explanation":"Een warme drank, meestal in de ochtend.","example":"Mijn vader drinkt koffie bij het ontbijt."},{"word":"de appel","explanation":"Een rond stuk fruit. Het is vaak rood of groen.","example":"Ik neem een appel mee naar mijn werk."},{"word":"het brood","explanation":"Eten dat je koopt bij de bakker. Je maakt er boterhammen van.","example":"Wij kopen elke dag vers brood."},{"word":"de groente","explanation":"Eten dat gezond is, bijvoorbeeld wortels of sla.","example":"Bij het avondeten eten we veel groente."},{"word":"lekker","explanation":"Iets dat je fijn vindt om te eten of te drinken.","example":"De soep is heel lekker."}],"grammar":[{"heading":"Het werkwoord ''eten'' en ''drinken'' (tegenwoordige tijd)","body":"Je gebruikt deze werkwoorden vaak. Bijvoorbeeld: ik eet, jij eet, hij eet, wij eten. En: ik drink, jij drinkt, zij drinkt, wij drinken."},{"heading":"Lidwoorden: de, het en een","body":"Bij een woord staat vaak ''de'' of ''het'', bijvoorbeeld: de appel, het brood. Weet je het woord nog niet? Dan gebruik je ''een'', bijvoorbeeld: een appel, een boterham."}],"exampleSentences":["Ik drink ''s ochtends een kop koffie.","Wij eten om zes uur het avondeten.","Het brood van de bakker is heel lekker.","Zij neemt een appel en een fles water mee.","Bij het eten drinken de kinderen melk."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000013', 'reading_text', 'Lees de tekst.', '{"text":"Sara woont in Utrecht. Zij begint de dag met een ontbijt. Ze eet twee boterhammen met kaas. Daarbij drinkt ze een kop thee. Sara houdt niet van koffie. Om twaalf uur eet ze de lunch op haar werk. Vaak neemt ze een appel en een boterham mee van huis. Ook drinkt ze veel water. In de avond kookt Sara samen met haar man. Zij eten graag rijst met groente en soms vis. Na het eten drinken ze thee. In het weekend eet Sara een keer buiten de deur. Dan gaat ze naar een klein restaurant. Ze vindt de soep daar heel lekker."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000013', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat drinkt Sara bij het ontbijt?","options":["Koffie","Thee","Water","Melk"]}'::jsonb, '{"correctIndex":1,"explanation":"In de tekst staat dat Sara bij het ontbijt een kop thee drinkt. Ze houdt niet van koffie."}'::jsonb, 2
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
