);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000014', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat wil Tom drinken?","options":["Thee","Water","Koffie","Melk"]}'::jsonb, '{"correctIndex":2,"explanation":"Tom zegt: ''Ik wil koffie, alsjeblieft.''"}'::jsonb, 3
);
