  'a1c00000-0000-4000-8000-000000000014', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wil Tom een appel?","options":["Ja, hij wil een appel","Nee, hij wil geen appel","Hij wil twee appels","Hij weet het niet"]}'::jsonb, '{"correctIndex":1,"explanation":"Tom zegt: ''Nee, dank je.'' Het brood en de koffie zijn genoeg."}'::jsonb, 4
);

-- schrijven — Eten en drinken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000015', 'A1', 'schrijven', 'Wat eet en drink je?',
  'In deze les leer je korte zinnen schrijven over eten en drinken.', 23, false, '{"intro":"In deze les leer je woorden over eten en drinken. Je leert schrijven wat je eet en wat je drinkt. Je oefent met korte, makkelijke zinnen.","learningGoals":["Je kent woorden over eten en drinken.","Je kunt schrijven wat je graag eet en drinkt.","Je gebruikt de werkwoorden ''eten'' en ''drinken'' in een zin.","Je schrijft een kort bericht over je eten."],"vocabulary":[{"word":"het brood","explanation":"Brood eet je vaak bij het ontbijt.","example":"Ik eet een boterham met brood."},{"word":"de kaas","explanation":"Kaas eet je vaak op je brood.","example":"Op mijn brood zit kaas."},{"word":"de appel","explanation":"Een appel is fruit. Fruit is gezond.","example":"Ik eet elke dag een appel."},{"word":"het water","explanation":"Water is een drankje. Je drinkt water uit een glas.","example":"Ik drink een glas water."},{"word":"de koffie","explanation":"Koffie is een warm drankje. Veel mensen drinken het ''s ochtends.","example":"Mijn vader drinkt koffie."},{"word":"de melk","explanation":"Melk is wit. Je drinkt het of je doet het in je koffie.","example":"In mijn thee doe ik melk."},{"word":"het ontbijt","explanation":"Het ontbijt is het eten in de ochtend.","example":"Ik eet mijn ontbijt om acht uur."},{"word":"lekker","explanation":"Iets is lekker als het heel goed smaakt.","example":"De soep is lekker."},{"word":"eten","explanation":"Eten doe je met je mond. Brood en fruit zijn eten.","example":"Wij eten samen aan tafel."},{"word":"drinken","explanation":"Drinken doe je met een drankje, zoals water of thee.","example":"De kinderen drinken melk."}],"grammar":[{"heading":"De werkwoorden ''eten'' en ''drinken''","body":"In de tegenwoordige tijd zeg je: ik eet, jij eet, hij/zij eet, wij eten. En: ik drink, jij drinkt, hij/zij drinkt, wij drinken. Voorbeeld: Ik eet een appel. Wij drinken water."},{"heading":"Zeggen wat je fijn vindt met ''graag''","body":"Wil je zeggen dat je iets fijn vindt? Gebruik het woord ''graag''. Het komt na het werkwoord. Voorbeeld: Ik drink graag thee. Zij eet graag brood."}],"exampleSentences":["Ik eet ''s ochtends een boterham met kaas.","Mijn zus drinkt graag koffie met melk.","Wil jij een glas water of een kopje thee?","De appel is heel lekker.","Wij eten om zes uur samen aan tafel."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000015', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een kort bericht aan een vriend of vriendin. Vertel wat je vandaag eet en drinkt. Schrijf wat je ''s ochtends, ''s middags en ''s avonds eet en drinkt. Gebruik woorden uit de les. Begin met ''Hoi'' en eindig met je naam. Schrijf hele zinnen.","minWords":35}'::jsonb, null, 1
);

-- spreken — Eten en drinken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000016', 'A1', 'spreken', 'Eten en drinken: iets bestellen',
  'In deze les leer je praten over eten en drinken en iets bestellen in een café.', 23, false, '{"intro":"In deze les leer je woorden over eten en drinken. Je leert vragen wat iets kost. Je leert ook iets bestellen in een café of restaurant.","learningGoals":["Je kent woorden voor eten en drinken.","Je kunt zeggen wat je lekker vindt.","Je kunt iets bestellen in een café.","Je kunt vragen wat iets kost."],"vocabulary":[{"word":"het brood","explanation":"Dit eet je vaak bij het ontbijt.","example":"Ik eet een boterham met kaas."},{"word":"het water","explanation":"Dit drink je als je dorst hebt.","example":"Mag ik een glas water?"},{"word":"de koffie","explanation":"Een warme drank. Veel mensen drinken dit in de ochtend.","example":"Ik drink graag koffie met melk."},{"word":"de thee","explanation":"Ook een warme drank, maar niet van koffiebonen.","example":"Wil je een kopje thee?"},{"word":"het fruit","explanation":"Bijvoorbeeld een appel of een banaan. Dit is gezond.","example":"Ik eet elke dag fruit."},{"word":"lekker","explanation":"Zeg je als eten of drinken heel goed smaakt.","example":"De soep is heel lekker."},{"word":"bestellen","explanation":"Zeggen wat je wilt eten of drinken in een café.","example":"Ik wil graag een broodje bestellen."},{"word":"de rekening","explanation":"Hier staat op hoeveel je moet betalen.","example":"Mag ik de rekening, alstublieft?"},{"word":"de honger","explanation":"Dit heb je als je wilt eten.","example":"Ik heb honger. Ik wil een broodje."},{"word":"de dorst","explanation":"Dit heb je als je wilt drinken.","example":"Ik heb dorst. Mag ik water?"}],"grammar":[{"heading":"Ik wil / Ik wil graag","body":"Met ''ik wil'' zeg je wat je graag hebt. Met ''graag'' is het beleefd. Voorbeeld: ''Ik wil een koffie.'' of ''Ik wil graag een broodje kaas.''"},{"heading":"Mag ik ...?","body":"Met ''Mag ik ...?'' vraag je beleefd om iets. Voorbeeld: ''Mag ik een glas water?'' of ''Mag ik de rekening, alstublieft?''"}],"exampleSentences":["Ik heb honger en dorst.","Mag ik een kopje koffie, alstublieft?","Ik wil graag een broodje kaas.","De thee is heel lekker.","Hoeveel kost een glas water?"]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000016', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je bent in een café. Je wilt iets eten en drinken bestellen. De ober komt naar je tafel en vraagt wat je wilt. Je bestelt iets en vraagt daarna om de rekening.","expectedPoints":["Zeg gedag: ''Hallo, goedemiddag.''","Bestel iets te drinken: ''Ik wil graag een koffie.''","Bestel iets te eten: ''Mag ik ook een broodje kaas?''","Vraag om de rekening: ''Mag ik de rekening, alstublieft?''"]}'::jsonb, null, 1
);

-- lezen — Boodschappen doen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000017', 'A1', 'lezen', 'Boodschappen doen in de winkel',
  'In deze les leer je eenvoudige woorden en zinnen over boodschappen doen.', 24, false, '{"intro":"In deze les lees je over boodschappen doen. Je leert woorden over eten en drinken. Je leert ook zinnen die je in de winkel kunt gebruiken.","learningGoals":["Je leert woorden over eten en drinken.","Je begrijpt een korte tekst over de supermarkt.","Je leert vragen over prijzen en producten.","Je oefent met lezen op A1-niveau."],"vocabulary":[{"word":"de boodschappen","explanation":"het eten en drinken dat je in de winkel koopt","example":"Ik doe elke week boodschappen."},{"word":"de supermarkt","explanation":"een grote winkel met veel eten en drinken","example":"De supermarkt is dichtbij mijn huis."},{"word":"de winkelwagen","explanation":"een wagen op wielen voor je boodschappen","example":"Ik doe het brood in de winkelwagen."},{"word":"het geld","explanation":"hiermee betaal je in de winkel","example":"Ik betaal het geld bij de kassa."},{"word":"de kassa","explanation":"de plek in de winkel waar je betaalt","example":"Bij de kassa staat een rij."},{"word":"goedkoop","explanation":"iets kost weinig geld","example":"De appels zijn vandaag goedkoop."},{"word":"duur","explanation":"iets kost veel geld","example":"De vis is duur."},{"word":"het boodschappenlijstje","explanation":"een papiertje met wat je wilt kopen","example":"Ik schrijf melk op mijn boodschappenlijstje."},{"word":"de prijs","explanation":"hoeveel geld iets kost","example":"Wat is de prijs van de kaas?"}],"grammar":[{"heading":"Lidwoord: de of het","body":"Bij een woord hoort ''de'' of ''het''. Bijvoorbeeld: de winkel, de melk, het brood, het geld. Je moet dit gewoon leren bij het woord."},{"heading":"Ik wil / ik heb nodig","body":"Je zegt wat je wilt kopen met ''ik wil'' of ''ik heb ... nodig''. Bijvoorbeeld: Ik wil brood. Ik heb melk nodig."}],"exampleSentences":["Ik ga naar de supermarkt.","Waar is het brood?","Ik koop melk, kaas en appels.","Wat kost dit?","Ik betaal bij de kassa."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000017', 'reading_text', 'Lees de tekst.', '{"text":"Anna doet vandaag boodschappen. Ze gaat naar de supermarkt in de buurt. Eerst maakt ze een boodschappenlijstje. Ze wil brood, melk, kaas en appels kopen. In de winkel pakt ze een winkelwagen. Het brood is vers en niet duur. De appels zijn vandaag goedkoop. Anna zoekt ook melk en kaas. Ze vindt alles snel. Dan loopt ze naar de kassa. Bij de kassa staat een korte rij. Anna wacht even. Ze betaalt met haar pinpas. De vrouw bij de kassa is aardig. Anna doet de boodschappen in haar tas. Daarna gaat ze weer naar huis. Ze is blij."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000017', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waar gaat Anna naartoe?","options":["Naar de school","Naar de supermarkt","Naar het werk","Naar de dokter"]}'::jsonb, '{"correctIndex":1,"explanation":"In de tekst staat dat Anna naar de supermarkt gaat om boodschappen te doen."}'::jsonb, 2
);
