-- schrijven — Boodschappen doen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000019', 'A1', 'schrijven', 'Boodschappen doen: een briefje schrijven',
  'Je leert eenvoudige woorden en zinnen om over boodschappen te schrijven.', 24, false, '{"intro":"In deze les leer je over boodschappen doen. Je leert woorden voor eten en drinken. Je oefent met een klein briefje schrijven.","learningGoals":["Je kent woorden voor eten en drinken.","Je kunt een klein boodschappenlijstje maken.","Je kunt een kort briefje schrijven.","Je gebruikt het woord ''ik koop'' in een zin."],"vocabulary":[{"word":"de winkel","explanation":"Een plaats waar je iets koopt.","example":"Ik ga naar de winkel."},{"word":"de supermarkt","explanation":"Een grote winkel voor eten en drinken.","example":"De supermarkt is open."},{"word":"het brood","explanation":"Eten van meel; je eet het vaak ''s ochtends.","example":"Ik koop een brood."},{"word":"de melk","explanation":"Een witte drank; die komt van de koe.","example":"De melk is in de koelkast."},{"word":"de appel","explanation":"Rood of groen fruit; je kunt het eten.","example":"Ik eet een appel."},{"word":"het geld","explanation":"Hiermee betaal je in de winkel.","example":"Ik heb geld bij me."},{"word":"de boodschappen","explanation":"Het eten en drinken dat je koopt.","example":"Ik doe boodschappen."},{"word":"het lijstje","explanation":"Een klein papier met woorden die je koopt.","example":"Ik maak een lijstje."},{"word":"betalen","explanation":"Geld geven voor iets in de winkel.","example":"Ik ga bij de kassa betalen."},{"word":"kopen","explanation":"Iets krijgen als je geld geeft.","example":"Ik wil kaas kopen."}],"grammar":[{"heading":"Het werkwoord ''kopen'' in de tegenwoordige tijd","body":"Je zegt: ik koop, jij koopt, hij koopt, wij kopen. Voorbeeld: Ik koop brood. Zij koopt melk."},{"heading":"Lidwoord: de of het","body":"Bij een woord hoort ''de'' of ''het''. Je zegt: de appel, de melk, het brood, het geld."}],"exampleSentences":["Ik ga naar de supermarkt.","Ik koop brood, melk en kaas.","Heb jij ook een appel nodig?","Ik maak eerst een lijstje.","Bij de kassa betaal ik met geld."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000019', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een kort briefje aan je huisgenoot. Je gaat naar de supermarkt. Schrijf wat je koopt (minstens drie dingen). Vraag of je huisgenoot ook iets nodig heeft. Begin met ''Hoi'' en eindig met je naam.","minWords":35}'::jsonb, null, 1
);

-- spreken — Boodschappen doen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000020', 'A1', 'spreken', 'Boodschappen doen in de winkel',
  'Je leert eenvoudige zinnen om boodschappen te doen en te betalen in een winkel.', 24, false, '{"intro":"In deze les leer je praten in de winkel. Je leert vragen naar producten en de prijs. Ook leer je hoe je netjes betaalt en dank je wel zegt.","learningGoals":["Je kunt vragen waar een product is.","Je kunt vragen hoeveel iets kost.","Je kunt een product bestellen bij de kassa of de balie.","Je kunt netjes groeten en bedanken."],"vocabulary":[{"word":"de winkel","explanation":"een plek waar je dingen koopt","example":"Ik ga naar de winkel."},{"word":"boodschappen doen","explanation":"eten en drinken kopen in de winkel","example":"Op zaterdag doe ik boodschappen."},{"word":"de prijs","explanation":"hoeveel geld iets kost","example":"Wat is de prijs van de melk?"},{"word":"kosten","explanation":"hoeveel geld je moet betalen","example":"Hoeveel kost het brood?"},{"word":"betalen","explanation":"geld geven voor iets","example":"Ik wil met de pin betalen."},{"word":"de kassa","explanation":"de plek waar je betaalt","example":"Ik sta bij de kassa."},{"word":"het geld","explanation":"waarmee je dingen koopt","example":"Ik heb geen geld bij me."},{"word":"de zak","explanation":"iets waarin je de boodschappen doet","example":"Mag ik een zak?"},{"word":"graag","explanation":"een net woord dat je zegt als je iets wilt","example":"Ik wil graag een kilo appels."},{"word":"alstublieft","explanation":"een net woord als je iets vraagt of geeft","example":"Een brood, alstublieft."}],"grammar":[{"heading":"Vragen met ''hoeveel'' en ''wat''","body":"Met ''hoeveel'' vraag je naar een aantal of een prijs. Met ''wat'' vraag je naar een ding. Voorbeeld: Hoeveel kost de kaas? Wat is dat?"},{"heading":"Ik wil / ik wil graag","body":"Met ''ik wil graag'' bestel je iets op een nette manier. Na ''ik wil'' komt het werkwoord of het product. Voorbeeld: Ik wil graag twee broodjes. Ik wil betalen."}],"exampleSentences":["Goedemiddag, waar is de melk?","Hoeveel kost een kilo appels?","Ik wil graag drie broodjes, alstublieft.","Kan ik met de pin betalen?","Dank u wel, tot ziens."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000020', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je bent in de supermarkt. Je zoekt brood en appels. Je vraagt aan de medewerker waar de appels zijn en hoeveel ze kosten. Daarna ga je naar de kassa en betaal je.","expectedPoints":["Groet de medewerker, bijvoorbeeld: Goedemiddag.","Vraag waar een product is, bijvoorbeeld: Waar zijn de appels?","Vraag naar de prijs, bijvoorbeeld: Hoeveel kosten de appels?","Bedank en groet, bijvoorbeeld: Dank u wel, tot ziens."]}'::jsonb, null, 1
);

-- lezen — Wonen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000021', 'A1', 'lezen', 'Wonen in Nederland',
  'In deze les lees je eenvoudige teksten over het huis en de kamers.', 25, false, '{"intro":"In deze les leer je woorden over wonen. Je leest over een huis en de kamers. De zinnen zijn kort en makkelijk.","learningGoals":["Je leert woorden over het huis.","Je leert de namen van kamers.","Je leest een korte tekst over wonen.","Je beantwoordt vragen over de tekst."],"vocabulary":[{"word":"het huis","explanation":"Hier woon je. Een huis heeft kamers.","example":"Wij wonen in een groot huis."},{"word":"de kamer","explanation":"Een deel van het huis, met muren en een deur.","example":"Mijn kamer is klein maar mooi."},{"word":"de keuken","explanation":"Hier maak je eten en koffie.","example":"In de keuken staat een grote tafel."},{"word":"de slaapkamer","explanation":"Hier slaap je. In de slaapkamer staat een bed.","example":"De slaapkamer is boven."},{"word":"de badkamer","explanation":"Hier was je je handen en je gaat onder de douche.","example":"De badkamer is naast de slaapkamer."},{"word":"de tuin","explanation":"Dit is buiten, naast of achter het huis. Hier groeien planten.","example":"In de zomer zit ik graag in de tuin."},{"word":"de buren","explanation":"De mensen die naast jou wonen.","example":"Mijn buren zijn heel aardig."},{"word":"de huur","explanation":"Het geld dat je elke maand voor het huis betaalt.","example":"Ik betaal de huur aan het begin van de maand."},{"word":"het raam","explanation":"Van glas. Hier kijk je naar buiten.","example":"Het raam in de woonkamer is groot."}],"grammar":[{"heading":"de of het","body":"Bij elk woord hoort ''de'' of ''het''. We zeggen ''de kamer'' en ''de tuin'', maar ''het huis'' en ''het raam''. Je moet dit per woord leren."},{"heading":"Wonen: ik woon, jij woont","body":"Het werkwoord is ''wonen''. Bijvoorbeeld: ''ik woon in Utrecht'', ''jij woont in een flat'', ''wij wonen samen''."}],"exampleSentences":["Ik woon in een klein huis.","De keuken is naast de woonkamer.","Mijn slaapkamer is boven.","In de tuin staat een boom.","De buren wonen naast ons."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000021', 'reading_text', 'Lees de tekst.', '{"text":"Sara woont in een flat in Rotterdam. De flat is niet groot, maar heel gezellig. Er zijn drie kamers. In de keuken maakt Sara elke dag eten. De woonkamer heeft een groot raam. Vanuit het raam kijkt zij naar de straat. De slaapkamer is klein. Daar staat een bed en een kast. De badkamer is naast de slaapkamer. Sara heeft geen tuin, maar zij heeft een klein balkon. Op het balkon staan veel planten. De buren zijn aardig. Elke maand betaalt Sara de huur. Zij woont hier al twee jaar en zij is heel blij met haar flat."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000021', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waar woont Sara?","options":["In een flat in Rotterdam","In een groot huis","In een tuin","In een winkel"]}'::jsonb, '{"correctIndex":0,"explanation":"In de tekst staat dat Sara in een flat in Rotterdam woont."}'::jsonb, 2
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000021', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat heeft Sara in plaats van een tuin?","options":["Een garage","Een balkon","Een keuken","Een auto"]}'::jsonb, '{"correctIndex":1,"explanation":"Sara heeft geen tuin, maar een klein balkon met veel planten."}'::jsonb, 3
);
