);

-- luisteren — Wonen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000022', 'A1', 'luisteren', 'Wonen: luisteren over jouw huis',
  'In deze les luister je naar een gesprek over waar mensen wonen.', 25, false, '{"intro":"In deze les leer je luisteren naar mensen die over hun huis praten. Je hoort woorden over kamers en over waar je woont. De zinnen zijn kort en makkelijk.","learningGoals":["Je begrijpt woorden over het huis en de kamers.","Je kunt luisteren waar iemand woont.","Je verstaat een kort gesprek over wonen.","Je herkent de vraag ''Waar woon je?''"],"vocabulary":[{"word":"het huis","explanation":"de plek waar je woont","example":"Ik woon in een groot huis."},{"word":"de kamer","explanation":"een ruimte in het huis","example":"Mijn kamer is klein."},{"word":"de keuken","explanation":"hier maak je eten","example":"In de keuken staat een tafel."},{"word":"de slaapkamer","explanation":"hier slaap je","example":"Mijn slaapkamer is boven."},{"word":"het appartement","explanation":"een huis in een groot gebouw","example":"Wij wonen in een appartement."},{"word":"de straat","explanation":"hier staan de huizen","example":"Ik woon in een rustige straat."},{"word":"de tuin","explanation":"een stuk grond bij het huis met planten","example":"In de tuin staat een boom."},{"word":"huren","explanation":"je betaalt elke maand geld voor een huis","example":"Wij huren een appartement in de stad."}],"grammar":[{"heading":"Het werkwoord ''wonen''","body":"Bij ik gebruik je ''woon''. Bij jij, hij en zij gebruik je ''woont''. Voorbeeld: Ik woon in Utrecht. Zij woont in Amsterdam."},{"heading":"De of het","body":"Sommige woorden krijgen ''de'' en andere ''het''. Voorbeeld: de keuken, de tuin, het huis, het appartement."}],"exampleSentences":["Ik woon in een klein huis.","Waar woon jij?","Mijn appartement heeft twee kamers.","De keuken is heel groot.","Wij hebben een mooie tuin."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000022', 'listening_clip', 'Beluister het gesprek.', '{"dialogue":[{"speaker":"v","name":"Sanne","text":"Hoi Tom, waar woon jij nu?"},{"speaker":"m","name":"Tom","text":"Ik woon in een appartement in de stad."},{"speaker":"v","name":"Sanne","text":"Leuk! Is het appartement groot?"},{"speaker":"m","name":"Tom","text":"Nee, het is klein. Ik heb twee kamers."},{"speaker":"v","name":"Sanne","text":"Heb je ook een tuin?"},{"speaker":"m","name":"Tom","text":"Nee, ik heb geen tuin. En jij, waar woon je?"},{"speaker":"v","name":"Sanne","text":"Ik woon in een huis met een tuin. De tuin is heel mooi."},{"speaker":"m","name":"Tom","text":"Wat fijn! Huur jij het huis?"},{"speaker":"v","name":"Sanne","text":"Ja, ik huur het huis samen met mijn zus."}]}'::jsonb, null, 1
);
