-- schrijven — Wonen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000023', 'A1', 'schrijven', 'Wonen: schrijven over je huis',
  'Je leert korte zinnen schrijven over je huis en je kamers.', 25, false, '{"intro":"In deze les leer je schrijven over wonen. Je leert woorden voor je huis en de kamers. Je schrijft korte, simpele zinnen over waar je woont.","learningGoals":["Je kent woorden voor het huis en de kamers.","Je schrijft korte zinnen over waar je woont.","Je kunt je adres opschrijven.","Je schrijft een kort bericht over je huis."],"vocabulary":[{"word":"het huis","explanation":"de plek waar je woont","example":"Ik woon in een klein huis."},{"word":"de kamer","explanation":"een ruimte in het huis","example":"Mijn kamer is niet groot."},{"word":"de keuken","explanation":"de kamer waar je eten maakt","example":"In de keuken staat een tafel."},{"word":"de slaapkamer","explanation":"de kamer waar je slaapt","example":"Mijn slaapkamer is boven."},{"word":"de badkamer","explanation":"de kamer met de douche en de wc","example":"De badkamer is klein."},{"word":"de woonkamer","explanation":"de kamer waar je zit en tv kijkt","example":"In de woonkamer staat een bank."},{"word":"de tuin","explanation":"een stuk grond buiten bij het huis","example":"Wij hebben een kleine tuin."},{"word":"de buurt","explanation":"de straten dicht bij je huis","example":"De buurt is rustig en fijn."},{"word":"het adres","explanation":"de straat en het nummer waar je woont","example":"Mijn adres is Kerkstraat 12."},{"word":"huren","explanation":"elke maand geld betalen voor een huis","example":"Wij huren een klein appartement."}],"grammar":[{"heading":"Er is en er zijn","body":"Je gebruikt ''er is'' voor een ding en ''er zijn'' voor meer dingen. Bijvoorbeeld: In mijn huis is er een keuken. In de tuin zijn er twee stoelen."},{"heading":"Het werkwoord wonen","body":"Wonen zegt waar je bent thuis. Ik woon, jij woont, hij woont, wij wonen. Bijvoorbeeld: Ik woon in Utrecht. Wij wonen in een flat."}],"exampleSentences":["Ik woon in een klein huis in de stad.","Mijn huis heeft drie kamers en een tuin.","In de keuken staat een grote tafel.","De slaapkamer is boven en de woonkamer is beneden.","Ik vind mijn buurt heel rustig en fijn."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000023', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een kort bericht aan een vriend over je huis. Vertel waar je woont, hoeveel kamers je huis heeft en welke kamer jij het fijnst vindt. Gebruik korte, simpele zinnen. Begin met ''Hoi'' en eindig met je naam.","minWords":40}'::jsonb, null, 1
);

-- spreken — Wonen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000024', 'A1', 'spreken', 'Praten over jouw huis',
  'Je leert vertellen waar en hoe je woont in eenvoudig Nederlands.', 25, false, '{"intro":"In deze les leer je praten over waar je woont. Je leert vertellen over jouw huis en jouw kamers. Je oefent met simpele zinnen over wonen.","learningGoals":["Ik kan vertellen waar ik woon.","Ik kan de kamers in mijn huis noemen.","Ik kan zeggen met wie ik woon.","Ik kan een vraag stellen over het huis van iemand anders."],"vocabulary":[{"word":"het huis","explanation":"de plek waar je woont en slaapt","example":"Mijn huis is niet groot."},{"word":"de kamer","explanation":"een ruimte in het huis","example":"Ik heb een mooie kamer."},{"word":"de keuken","explanation":"de kamer waar je eten maakt","example":"In de keuken kook ik soep."},{"word":"de slaapkamer","explanation":"de kamer waar je slaapt","example":"Mijn slaapkamer is klein."},{"word":"de badkamer","explanation":"de kamer waar je doucht en je wast","example":"De badkamer is naast de keuken."},{"word":"de flat","explanation":"een woning in een groot gebouw met veel woningen","example":"Ik woon in een flat op de derde verdieping."},{"word":"de tuin","explanation":"de ruimte buiten bij het huis met planten","example":"Wij hebben een kleine tuin achter het huis."},{"word":"huren","explanation":"elke maand geld betalen voor een woning","example":"Ik huur een kamer in de stad."},{"word":"de buurman","explanation":"de man die naast jou woont","example":"Mijn buurman is heel aardig."},{"word":"wonen","explanation":"op een plek zijn waar je slaapt en leeft","example":"Ik woon in Utrecht."}],"grammar":[{"heading":"Het werkwoord ''wonen''","body":"Het werkwoord ''wonen'' gebruik je om te zeggen waar je bent. Je zegt: ik woon, jij woont, hij/zij woont, wij wonen. Voorbeeld: Ik woon in Amsterdam. Jij woont in een flat."},{"heading":"Voorzetsels: in en op","body":"Je gebruikt ''in'' voor een plaats of stad en vaak ''op'' voor een verdieping of adres. Voorbeeld: Ik woon in Rotterdam. Ik woon op de tweede verdieping."}],"exampleSentences":["Ik woon in een kleine flat.","Mijn huis heeft drie kamers.","Ik woon samen met mijn familie.","De keuken is groot en licht.","Waar woon jij?"]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000024', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je ontmoet een nieuwe klasgenoot op de taalschool. Vertel waar je woont en hoe jouw huis is. Stel ook een vraag over het huis van de ander.","expectedPoints":["Ik woon in ... (stad of wijk).","Ik woon in een huis / een flat.","Mijn huis heeft ... kamers.","Waar woon jij?"]}'::jsonb, null, 1
);

-- lezen — Openbaar vervoer
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000025', 'A1', 'lezen', 'Met de bus en de trein',
  'Je leert eenvoudige woorden en zinnen over het openbaar vervoer in Nederland.', 26, false, '{"intro":"In deze les lees je over het openbaar vervoer. Je leert woorden over de bus, de trein en de tram. Je leert ook hoe je een kaartje koopt en naar de tijd vraagt.","learningGoals":["Je begrijpt eenvoudige woorden over het openbaar vervoer.","Je leest een korte tekst over reizen met de bus en de trein.","Je begrijpt hoe je een kaartje koopt.","Je vindt informatie over de tijd in een korte tekst."],"vocabulary":[{"word":"de bus","explanation":"Een groot voertuig met veel stoelen. Veel mensen reizen samen.","example":"Ik ga met de bus naar de stad."},{"word":"de trein","explanation":"Een lang voertuig dat op rails rijdt. De trein is snel.","example":"De trein naar Amsterdam vertrekt om acht uur."},{"word":"de tram","explanation":"Een voertuig op rails in de stad. De tram stopt vaak.","example":"In Amsterdam pak ik de tram."},{"word":"het station","explanation":"De plek waar de trein stopt. Hier stap je in en uit.","example":"Ik wacht op het station op mijn vriend."},{"word":"de halte","explanation":"De plek waar de bus of de tram stopt.","example":"De bus stopt bij de halte voor de school."},{"word":"het kaartje","explanation":"Papier of een pas voor de reis. Je betaalt voor het kaartje.","example":"Ik koop een kaartje bij de automaat."},{"word":"instappen","explanation":"In de bus, de trein of de tram gaan.","example":"De mensen stappen in de trein."},{"word":"uitstappen","explanation":"Uit de bus, de trein of de tram gaan.","example":"Bij het station stap ik uit."},{"word":"vertrekken","explanation":"Weggaan. De bus of de trein rijdt weg.","example":"De trein vertrekt om negen uur."},{"word":"op tijd","explanation":"Niet te laat. Precies goed met de tijd.","example":"De bus is vandaag op tijd."}],"grammar":[{"heading":"Met de bus, met de trein","body":"Voor vervoer gebruik je het woord ''met''. Je zegt: ''Ik ga met de bus.'' of ''Ik reis met de trein.'' Ook goed: ''Wij gaan met de tram naar huis.''"},{"heading":"Hoe laat? De tijd","body":"Je vraagt naar de tijd met ''Hoe laat?''. Bijvoorbeeld: ''Hoe laat vertrekt de trein?'' Het antwoord is: ''De trein vertrekt om acht uur.'' Je gebruikt ''om'' voor de tijd."}],"exampleSentences":["Ik ga elke dag met de bus naar mijn werk.","Het station is dichtbij mijn huis.","Hoe laat vertrekt de trein naar Utrecht?","Ik koop een kaartje bij de automaat.","De tram stopt bij de halte in het centrum."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000025', 'reading_text', 'Lees de tekst.', '{"text":"Sara woont in Rotterdam. Elke dag gaat zij met de trein naar haar werk in Den Haag. Zij loopt naar het station. Het station is dichtbij. Bij de automaat koopt Sara een kaartje. De trein vertrekt om half acht. Sara wacht op het perron. De trein is op tijd. Zij stapt in en zoekt een stoel bij het raam. De reis duurt dertig minuten. In Den Haag stapt Sara uit. Dan pakt zij de tram naar het kantoor. De tram stopt bij de halte voor het gebouw. Sara is blij. Zij is nooit te laat op haar werk."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000025', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waar woont Sara?","options":["In Den Haag","In Rotterdam","In Utrecht","In Amsterdam"]}'::jsonb, '{"correctIndex":1,"explanation":"In de tekst staat: ''Sara woont in Rotterdam.''"}'::jsonb, 2
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000025', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Hoe gaat Sara naar haar werk?","options":["Met de bus","Met de auto","Met de trein","Met de fiets"]}'::jsonb, '{"correctIndex":2,"explanation":"Sara gaat elke dag met de trein naar haar werk in Den Haag."}'::jsonb, 3
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000025', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat doet Sara in Den Haag na de trein?","options":["Zij pakt de tram","Zij loopt naar huis","Zij wacht op de bus","Zij koopt een kaartje"]}'::jsonb, '{"correctIndex":0,"explanation":"In de tekst staat: ''Dan pakt zij de tram naar het kantoor.''"}'::jsonb, 4
);

-- luisteren — Openbaar vervoer
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000026', 'A1', 'luisteren', 'Met de bus en de trein',
  'Je leert luisteren naar korte gesprekken over reizen met bus, tram en trein.', 26, false, '{"intro":"In deze les leer je luisteren naar het openbaar vervoer. Je hoort woorden over de bus, de tram en de trein. Je leert ook hoe je vraagt hoe laat en waar iets vertrekt.","learningGoals":["Je herkent woorden over het openbaar vervoer.","Je begrijpt een kort gesprek over de bus en de trein.","Je verstaat tijden en haltes.","Je begrijpt een simpele vraag om hulp."],"vocabulary":[{"word":"de bus","explanation":"Een groot voertuig op de weg met veel stoelen voor mensen.","example":"Ik ga met de bus naar het werk."},{"word":"de trein","explanation":"Een lang voertuig dat op rails rijdt tussen steden.","example":"De trein naar Utrecht is snel."},{"word":"de tram","explanation":"Een voertuig op rails in de stad.","example":"De tram stopt hier voor het station."},{"word":"de halte","explanation":"De plek waar de bus of tram stopt en je kunt instappen.","example":"Ik wacht bij de halte op de bus."},{"word":"het station","explanation":"De plek waar de treinen aankomen en vertrekken.","example":"Het station is dichtbij mijn huis."},{"word":"het kaartje","explanation":"Papier of een chip waarmee je mag reizen.","example":"Ik koop een kaartje voor de trein."},{"word":"instappen","explanation":"In de bus, tram of trein gaan.","example":"We moeten hier instappen."},{"word":"uitstappen","explanation":"Uit de bus, tram of trein gaan.","example":"Ik stap bij het station uit."},{"word":"vertrekken","explanation":"Weggaan; de trein of bus gaat rijden.","example":"De trein vertrekt om tien uur."},{"word":"overstappen","explanation":"Van de ene bus of trein naar de andere gaan.","example":"In Amsterdam moet ik overstappen."}],"grammar":[{"heading":"Met de bus / met de trein","body":"Je gebruikt ''met'' om te zeggen hoe je reist. Bijvoorbeeld: ''Ik ga met de bus.'' of ''Wij reizen met de trein.''"},{"heading":"Hoe laat vertrekt de trein?","body":"Met ''hoe laat'' vraag je naar de tijd. Bijvoorbeeld: ''Hoe laat vertrekt de bus?'' Het antwoord is een tijd: ''De bus vertrekt om acht uur.''"}],"exampleSentences":["De bus komt om negen uur.","Waar is de halte?","Ik koop een kaartje bij het station.","We stappen hier uit.","De trein naar Rotterdam vertrekt van spoor twee."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000026', 'listening_clip', 'Beluister het gesprek.', '{"dialogue":[{"speaker":"v","name":"Sanne","text":"Hallo, gaat deze bus naar het station?"},{"speaker":"m","name":"Tom","text":"Ja, deze bus gaat naar het station."},{"speaker":"v","name":"Sanne","text":"Fijn. Hoe laat vertrekt de bus?"},{"speaker":"m","name":"Tom","text":"De bus vertrekt om half tien."},{"speaker":"v","name":"Sanne","text":"En hoeveel haltes is het?"},{"speaker":"m","name":"Tom","text":"Het is vier haltes. Dan stap je uit."},{"speaker":"v","name":"Sanne","text":"Heb ik een kaartje nodig?"},{"speaker":"m","name":"Tom","text":"Ja, je koopt een kaartje bij de chauffeur."},{"speaker":"v","name":"Sanne","text":"Dank je wel. Dat is duidelijk."},{"speaker":"m","name":"Tom","text":"Graag gedaan. Goede reis!"}]}'::jsonb, null, 1
);
