-- schrijven — Openbaar vervoer
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000027', 'A1', 'schrijven', 'Met de bus en de trein',
  'In deze les leer je eenvoudige zinnen schrijven over reizen met het openbaar vervoer.', 26, false, '{"intro":"In deze les leer je woorden over het openbaar vervoer. Je leert schrijven over de bus, de trein en de tram. Je oefent korte zinnen over waar je naartoe gaat en hoe laat.","learningGoals":["Je kent woorden over het openbaar vervoer.","Je kunt schrijven hoe je reist.","Je kunt schrijven waar je naartoe gaat.","Je kunt een kort bericht schrijven over je reis."],"vocabulary":[{"word":"de bus","explanation":"Een groot voertuig op de weg voor veel mensen.","example":"Ik ga met de bus naar de stad."},{"word":"de trein","explanation":"Een lang voertuig op het spoor.","example":"De trein naar Amsterdam vertrekt om negen uur."},{"word":"de tram","explanation":"Een voertuig op rails in de stad.","example":"De tram stopt voor het station."},{"word":"het station","explanation":"De plek waar de trein stopt.","example":"Ik wacht op het station op mijn vriendin."},{"word":"de halte","explanation":"De plek waar de bus of tram stopt.","example":"De halte is naast de winkel."},{"word":"het kaartje","explanation":"Papier of een kaart die je koopt om te reizen.","example":"Ik koop een kaartje voor de trein."},{"word":"instappen","explanation":"In de bus, tram of trein gaan.","example":"Wij stappen in bij de halte."},{"word":"uitstappen","explanation":"Uit de bus, tram of trein gaan.","example":"Ik stap uit op het station."},{"word":"vertrekken","explanation":"Weggaan van een plek.","example":"De bus vertrekt om acht uur."},{"word":"aankomen","explanation":"Op een plek komen.","example":"Ik kom om tien uur aan in Utrecht."}],"grammar":[{"heading":"met de + vervoer","body":"Je zegt hoe je reist met ''met de'' of ''met het''. Bijvoorbeeld: Ik ga met de bus. Ik ga met de trein. Ik ga met het openbaar vervoer."},{"heading":"naar + plaats","body":"Je zegt waar je naartoe gaat met ''naar''. Bijvoorbeeld: Ik ga naar het station. Wij gaan naar Rotterdam."}],"exampleSentences":["Ik ga met de trein naar mijn werk.","De bus vertrekt om half negen.","Wij stappen in bij de halte voor het huis.","Ik koop een kaartje bij de automaat.","De tram komt om drie uur aan bij het station."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000027', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een kort bericht aan een vriend of vriendin. Vertel hoe je naar de stad reist. Schrijf met welk vervoer je gaat (de bus, de trein of de tram), hoe laat je vertrekt en waar je uitstapt. Gebruik korte, eenvoudige zinnen.","minWords":35}'::jsonb, null, 1
);

-- spreken — Openbaar vervoer
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000028', 'A1', 'spreken', 'Met de bus en de trein',
  'Je leert praten over het openbaar vervoer en een kaartje kopen.', 26, false, '{"intro":"In deze les leer je praten over het openbaar vervoer. Je leert een kaartje kopen en de weg vragen. Je oefent met heel makkelijke zinnen.","learningGoals":["Je kunt een kaartje kopen bij het loket.","Je kunt vragen hoe laat de bus of de trein gaat.","Je kunt vragen waar je moet uitstappen.","Je kunt zeggen waar je naartoe wilt."],"vocabulary":[{"word":"de bus","explanation":"Een grote auto voor veel mensen. De bus rijdt op de weg.","example":"Ik ga met de bus naar mijn werk."},{"word":"de trein","explanation":"Die rijdt op het spoor en gaat heel snel.","example":"De trein naar Utrecht vertrekt om drie uur."},{"word":"het kaartje","explanation":"Dit koop je om te mogen reizen. Zonder kaartje mag je niet mee.","example":"Ik koop een kaartje naar Amsterdam."},{"word":"de halte","explanation":"De plek waar de bus stopt en waar je in- en uitstapt.","example":"Ik wacht bij de halte op de bus."},{"word":"het station","explanation":"Het gebouw waar de treinen komen en vertrekken.","example":"Het station is dichtbij mijn huis."},{"word":"instappen","explanation":"In de bus of de trein gaan.","example":"Wij stappen in bij het station."},{"word":"uitstappen","explanation":"Uit de bus of de trein gaan.","example":"Ik stap uit bij de volgende halte."},{"word":"overstappen","explanation":"Uit de ene bus of trein gaan en in een andere gaan.","example":"Ik moet in Den Haag overstappen."},{"word":"vertrekken","explanation":"Weggaan. De trein gaat rijden.","example":"Hoe laat vertrekt de bus?"},{"word":"het perron","explanation":"De plek op het station waar je op de trein wacht.","example":"De trein staat op perron twee."}],"grammar":[{"heading":"Reizen met ''met de''","body":"Je zegt hoe je reist met ''met de'' of ''met het''. Bijvoorbeeld: ''Ik ga met de bus.'' of ''Ik ga met de trein.'' Je gebruikt dit voor elk vervoer."},{"heading":"Vragen stellen met ''hoe laat'' en ''waar''","body":"Een vraag begint vaak met een vraagwoord. Met ''hoe laat'' vraag je naar de tijd: ''Hoe laat gaat de trein?'' Met ''waar'' vraag je naar een plek: ''Waar is de halte?''"}],"exampleSentences":["Ik ga met de bus naar het centrum.","Hoe laat vertrekt de trein naar Rotterdam?","Waar moet ik uitstappen?","Een kaartje naar Amsterdam, alstublieft.","Ik moet in Utrecht overstappen."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000028', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je bent op het station. Je wilt met de trein naar Amsterdam. Je koopt een kaartje bij het loket en je vraagt hoe laat de trein gaat en van welk perron.","expectedPoints":["Zeg waar je naartoe wilt: ''Ik wil naar Amsterdam.''","Vraag om een kaartje: ''Een kaartje naar Amsterdam, alstublieft.''","Vraag naar de tijd: ''Hoe laat vertrekt de trein?''","Vraag naar het perron: ''Van welk perron vertrekt de trein?''"]}'::jsonb, null, 1
);

-- lezen — Bij de dokter
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free, content) values (
  'a1c00000-0000-4000-8000-000000000029', 'A1', 'lezen', 'Bij de dokter',
  'In deze les leer je eenvoudige woorden en zinnen voor een bezoek aan de dokter.', 27, false, '{"intro":"In deze les lees je over een bezoek aan de dokter. Je leert woorden over ziek zijn en over de dokter. Je leert ook hoe je een afspraak maakt.","learningGoals":["Je leert woorden over ziek zijn.","Je leert een korte tekst over de dokter lezen.","Je leert vragen bij de tekst beantwoorden.","Je leert hoe je vertelt wat je hebt."],"vocabulary":[{"word":"de dokter","explanation":"De persoon die je helpt als je ziek bent.","example":"Ik ga naar de dokter."},{"word":"ziek","explanation":"Als je niet gezond bent en je voelt je niet goed.","example":"Ik ben ziek en ik blijf thuis."},{"word":"de afspraak","explanation":"Een tijd waarop je bij de dokter mag komen.","example":"Ik heb een afspraak om tien uur."},{"word":"de pijn","explanation":"Iets doet zeer in je lichaam.","example":"Ik heb pijn in mijn buik."},{"word":"de koorts","explanation":"Je lichaam is heel warm als je ziek bent.","example":"Het kind heeft koorts."},{"word":"het medicijn","explanation":"Dit neem je in om beter te worden.","example":"De dokter geeft mij een medicijn."},{"word":"de wachtkamer","explanation":"De kamer waar je wacht op de dokter.","example":"Ik zit in de wachtkamer."},{"word":"beter","explanation":"Als je weer gezond bent en niet meer ziek.","example":"Na een week ben ik weer beter."},{"word":"de keel","explanation":"Het deel in je hals waar je mee slikt en praat.","example":"Mijn keel doet pijn."}],"grammar":[{"heading":"Ik heb ... (vertellen wat je voelt)","body":"Met ''ik heb'' vertel je wat er is. Bijvoorbeeld: ''Ik heb pijn.'' of ''Ik heb koorts.'' Je zegt ook: ''Ik heb pijn in mijn buik.''"},{"heading":"Het werkwoord ''zijn'': ik ben ziek","body":"Je gebruikt ''zijn'' om te zeggen hoe je bent. Bijvoorbeeld: ''Ik ben ziek.'' en ''Jij bent beter.'' We zeggen: ik ben, jij bent, hij is."}],"exampleSentences":["Ik voel me niet goed.","Ik maak een afspraak bij de dokter.","In de wachtkamer zijn veel mensen.","De dokter vraagt: wat heeft u?","Ik neem elke dag een medicijn."]}'::jsonb
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'a1c00000-0000-4000-8000-000000000029', 'reading_text', 'Lees de tekst.', '{"text":"Sara voelt zich niet goed. Ze is ziek. Ze heeft pijn in haar keel en ze heeft koorts. Sara belt de dokter. Ze maakt een afspraak voor tien uur. Om tien uur gaat Sara naar de dokter. Eerst zit ze in de wachtkamer. Er zijn veel mensen. Sara wacht tien minuten. Dan komt ze bij de dokter. De dokter kijkt in haar keel. De dokter zegt: u bent een beetje ziek. U hebt een medicijn nodig. Sara krijgt een medicijn. Ze neemt het medicijn elke dag. Na een week is Sara weer beter. Ze is heel blij."}'::jsonb, null, 1
);
