  'a1c00000-0000-4000-8000-000000000030', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waar heeft Fatima pijn?","options":["In haar been","In haar buik","In haar keel","In haar arm"]}'::jsonb, '{"correctIndex":2,"explanation":"Fatima zegt dat ze veel pijn heeft in haar keel."}'::jsonb, 3
);
